/**
 * Post-build patch: bypass middleware for /api/v1/* so API routes are not
 * blocked by the "Dynamic require of middleware-manifest.json" crash on
 * Cloudflare Workers. Only the server handler is invoked for these paths.
 *
 * Patches .open-next/worker.js (generated by opennextjs-cloudflare build).
 */

const fs = require("fs");
const path = require("path");

const workerPath = path.join(__dirname, "..", ".open-next", "worker.js");
if (!fs.existsSync(workerPath)) {
  console.warn("patch-worker-bypass-api-middleware: .open-next/worker.js not found, skip");
  process.exit(0);
}

let code = fs.readFileSync(workerPath, "utf8");

const marker =
  "            // - `Request`s are handled by the Next server\n            const reqOrResp = await middlewareHandler(request, env, ctx);";
const alreadyBypassMarker = "url.pathname.startsWith(\"/api/v1/\")";
const replacement = `            // Bypass middleware for /api/v1/* (avoids middleware-manifest.json dynamic require crash on Workers)
            let reqOrResp;
            if (url.pathname.startsWith("/api/v1/")) {
                reqOrResp = request;
            } else {
                const { handler: middlewareHandler } = await import("./middleware/handler.mjs");
                reqOrResp = await middlewareHandler(request, env, ctx);
            }`;

if (code.includes(marker)) {
  code = code.replace(marker, replacement);
} else if (code.includes(alreadyBypassMarker) && code.includes("reqOrResp = await middlewareHandler")) {
  code = code.replace(
    "reqOrResp = await middlewareHandler(request, env, ctx);",
    "const { handler: middlewareHandler } = await import(\"./middleware/handler.mjs\");\n                reqOrResp = await middlewareHandler(request, env, ctx);"
  );
} else if (!code.includes(alreadyBypassMarker)) {
  console.warn("patch-worker-bypass-api-middleware: bypass marker not found in worker.js (format may have changed), skip");
}

// Remove top-level import of middleware so it is only loaded for non-API requests (avoids middleware-manifest require at Worker init)
code = code.replace(
  /import \{ handler as middlewareHandler \} from "\.\/middleware\/handler\.mjs";\n/g,
  "// middleware loaded dynamically for non-API paths only\n"
);

// Stub global require for middleware-manifest so server handler does not throw (nodejs_compat uses global require)
const stubRequireMarker = "return runWithCloudflareRequestContext(request, env, ctx, async () => {\n            const response = maybeGetSkewProtectionResponse(request);";
const stubRequireReplacement = `return runWithCloudflareRequestContext(request, env, ctx, async () => {
            if (typeof globalThis.require === "function") {
                const _origRequire = globalThis.require;
                globalThis.require = function (id) {
                    if (typeof id === "string" && id.includes("middleware-manifest")) return { version: 3, middleware: {}, functions: {}, sortedMiddleware: [] };
                    return _origRequire.apply(this, arguments);
                };
            }
            const response = maybeGetSkewProtectionResponse(request);`;
if (code.includes(stubRequireMarker) && !code.includes("_origRequire")) {
    code = code.replace(stubRequireMarker, stubRequireReplacement);
}

fs.writeFileSync(workerPath, code, "utf8");
console.log("patch-worker-bypass-api-middleware: patched .open-next/worker.js (bypass middleware for /api/v1/*)");
